import boto3
import json
import logging
from typing import Dict, Any, Callable
from concurrent.futures import ThreadPoolExecutor
import time

class SQSWorker:
    def __init__(self, queue_url: str, max_workers: int = 10, visibility_timeout: int = 30):
        self.queue_url = queue_url
        self.max_workers = max_workers
        self.visibility_timeout = visibility_timeout
        self.sqs_client = boto3.client('sqs')
        self.message_processors: Dict[str, Callable] = {}
        self.executor = ThreadPoolExecutor(max_workers=max_workers)
        self.logger = logging.getLogger(__name__)
        
    def register_processor(self, message_type: str, processor_func: Callable):
        """Register a processor function for a specific message type"""
        self.message_processors[message_type] = processor_func
        
    def _parse_message(self, message_body: str) -> Dict[str, Any]:
        """Parse message body and extract message type and data"""
        try:
            if isinstance(message_body, str):
                data = json.loads(message_body)
            else:
                data = message_body
            return data
        except json.JSONDecodeError as e:
            self.logger.error(f"Failed to parse message: {e}")
            raise ValueError(f"Invalid JSON message: {message_body}")
            
    def _process_message(self, message: Dict[str, Any]) -> bool:
        """Process a single message based on its type"""
        try:
            message_body = message.get('Body')
            if not message_body:
                self.logger.warning("Empty message body")
                return True
                
            parsed_data = self._parse_message(message_body)
            message_type = parsed_data.get('type')
            
            if not message_type:
                self.logger.warning("Message has no type field")
                return False
                
            processor = self.message_processors.get(message_type)
            if not processor:
                self.logger.warning(f"No processor registered for message type: {message_type}")
                return False
                
            # Execute processor
            processor(parsed_data)
            self.logger.info(f"Successfully processed message type: {message_type}")
            return True
            
        except Exception as e:
            self.logger.error(f"Error processing message: {e}")
            return False
            
    def _delete_message(self, receipt_handle: str) -> bool:
        """Delete message from queue"""
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            return True
        except Exception as e:
            self.logger.error(f"Failed to delete message: {e}")
            return False
            
    def process_messages(self, max_messages: int = 10, wait_time: int = 20):
        """Poll and process messages from SQS"""
        while True:
            try:
                response = self.sqs_client.receive_message(
                    QueueUrl=self.queue_url,
                    MaxNumberOfMessages=min(max_messages, 10),
                    WaitTimeSeconds=wait_time,
                    VisibilityTimeout=self.visibility_timeout
                )
                
                messages = response.get('Messages', [])
                if not messages:
                    time.sleep(1)
                    continue
                    
                # Process messages in parallel
                futures = []
                for message in messages:
                    receipt_handle = message['ReceiptHandle']
                    future = self.executor.submit(self._process_message, message)
                    futures.append((future, receipt_handle))
                    
                # Wait for all processing to complete and delete messages
                for future, receipt_handle in futures:
                    try:
                        success = future.result(timeout=30)
                        if success:
                            self._delete_message(receipt_handle)
                    except Exception as e:
                        self.logger.error(f"Error processing message: {e}")
                        
            except Exception as e:
                self.logger.error(f"Error in message processing loop: {e}")
                time.sleep(5)

